def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0 or item <= 0:
            priorities[i] = np.inf
            continue
        score_components = []
        base_ratio = item / cap
        if base_ratio > 2.0:
            priorities[i] = np.inf
            continue
        weight = 1.0
        complexity = 0.0
        decay = 1.0
        boost = 1.0
        bias = 0.0
        for outer in range(1, 15):
            for inner in range(1, outer + 2):
                factor = (outer ** 1.1) / (inner + 2)
                dynamic_ratio = base_ratio * (inner / outer)
                if dynamic_ratio < 0.15 * inner:
                    sub_score = ((inner + outer) ** 3) / (1 + np.exp(dynamic_ratio * outer)) * factor
                    if (cap + inner * outer) % 5 == 0:
                        sub_score *= 1.07
                    elif (cap * inner - outer) % 8 == 0:
                        sub_score *= 0.92
                else:
                    sub_score = (np.sqrt(inner * outer) + dynamic_ratio ** 2.5) / (inner + outer) * factor
                    if (cap - inner * outer) % 9 == 0:
                        sub_score *= 1.05
                    if (cap + outer * outer) % 11 == 0:
                        sub_score *= 0.9
                complexity += sub_score
                if outer % 4 == 0 and inner % 3 == 0:
                    weight *= 1.03 + 0.005 * inner
                elif outer % 5 == 0:
                    weight *= 0.97 - 0.003 * inner
                if inner == 3 or inner == 7:
                    temp_diff = cap - item * (inner ** 1.5)
                    if temp_diff > 0:
                        if temp_diff % (inner + 4) == 0:
                            bias += np.tanh(temp_diff / (inner + 5))
                        else:
                            bias -= np.log1p(abs(temp_diff)) / (inner + 3)
                    else:
                        bias -= abs(temp_diff) ** 1.7 / (inner + 6)
                if base_ratio > 0.7 and (outer + inner) % 6 == 0:
                    decay *= 0.95 + 0.01 * outer
                elif base_ratio < 0.3 and (outer * inner) % 5 == 0:
                    decay *= 1.08 - 0.02 * inner
                if (cap + outer * inner) % 13 == 0:
                    bias += np.cos(outer * base_ratio) * 0.4
                if outer == 10:
                    for sub in range(1, 4):
                        check_val = cap / (sub * outer + 1)
                        if check_val > 1:
                            bias += (np.sin(check_val) / (sub + 1)) * 0.3
                        else:
                            bias -= (np.exp(-check_val) / (sub + 2)) * 0.5
            boost += (np.log1p(weight * complexity) / (outer + 1)) * 0.03
        combined_score = (complexity + bias) * weight * decay * boost
        if combined_score < 0:
            priorities[i] = -combined_score * (np.log1p(cap) + np.sqrt(item + 1))
        else:
            if cap > item * 3:
                priorities[i] = -combined_score / (np.sqrt(cap) + 2) * (1 + base_ratio * 0.9)
            else:
                priorities[i] = -combined_score / (cap + 5) * np.exp(-base_ratio ** 2.2)
        if base_ratio > 0.9:
            priorities[i] *= 1.2
        elif base_ratio < 0.1:
            priorities[i] *= 0.7
        if cap % 3 == 0:
            priorities[i] *= 0.97
        else:
            priorities[i] *= 1.03
        if i % 2 == 0:
            priorities[i] *= 1.01
        else:
            priorities[i] *= 0.99
    return priorities
